    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // 1. Create a buffer_adaptor from the input span
    // Note: Need to convert const span to non-const for buffer_adaptor
    std::span<uint8_t> non_const_buffer(buffer.data(), buffer.size());
    hexi::buffer_adaptor<std::span<uint8_t>> adaptor(non_const_buffer);

    // 2. Use buffer_adaptor's preview function to read data_type without advancing read pointer
    adaptor.preview(&result.data_type, sizeof(uint8_t));

    // 3. Check available data size using buffer_adaptor's size function
    if (adaptor.size() < sizeof(uint8_t) + sizeof(uint32_t)) {
        // Not enough data for header
        return result;
    }

    // 4. Read item_count based on data_type
    uint32_t item_count;
    adaptor.read(&item_count, sizeof(uint32_t));

    // 5. Calculate required bytes for items based on data_type
    size_t item_bytes = 0;
    if (result.data_type == 0) { // integers
        item_bytes = item_count * sizeof(uint32_t);
    } else if (result.data_type == 1) { // floats
        item_bytes = item_count * sizeof(float);
    }

    // Check if we have enough data for the items
    if (adaptor.size() < item_bytes) {
        return result; // Incomplete data
    }

    // 6. Read items using binary_stream
    // Create binary_stream from the buffer_adaptor
    hexi::binary_stream<hexi::buffer_adaptor<std::span<uint8_t>>> stream(adaptor);

    if (result.data_type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream.read(&result.int_items[i]);
        }
    } else if (result.data_type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream.read(&result.float_items[i]);
        }
    }

    return result;
}

