    int* block2 = allocator.allocate();
    std::cout << "3. Allocated second block (" << block2 << ")\n";
    std::cout << "   - This calls pop(), removing from free list head\n\n";

    // Show that the addresses are the same (from free list)
    if (block1 == block2) {
        std::cout << "4. Verification: Both blocks have the same address!\n";
        std::cout << "   - Confirms allocation came from free list\n";
