    buffer.copy(data, length);
}

template<typename T>
void peek_value_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, T& value) {
    // Use the template copy method to copy a single value without advancing read pointer
    buffer.copy(&value);
}

bool peek_and_compare(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, const void* expected, std::size_t length) {
    // Create a temporary buffer to hold the peeked data
    std::vector<std::byte> temp_buffer(length);

    // Use the non-template copy method to copy data without advancing read pointer
    buffer.copy(temp_buffer.data(), length);

    // Compare the copied data with expected data using memcmp
    return std::memcmp(temp_buffer.data(), expected, length) == 0;
}

